type StreamFeedQueryContract = {
  country: StreamCountryCode;
  type: FeedType;
  category: Category;
  nearby: boolean;
  search: string;
  realDataOnly: true;
  fakeInjectionAllowed: false;
  providerConfigured: false;
};

function buildStreamFeedQueryContract(params: {
  country: StreamCountryCode;
  type: FeedType;
  category: Category;
  nearby: boolean;
  query: string;
}): StreamFeedQueryContract {
  return {
    country: params.country,
    type: params.type,
    category: params.category,
    nearby: params.nearby,
    search: params.query.trim(),
    realDataOnly: true,
    fakeInjectionAllowed: false,
    providerConfigured: false,
  };
}

function acceptsOnlyRealStreamCards(streams: LiveStreamCard[], contract: StreamFeedQueryContract): LiveStreamCard[] {
  if (!contract.realDataOnly || contract.fakeInjectionAllowed || !contract.providerConfigured) {
    return [];
  }

  return streams;
}

function getFeedStateText(status: FeedStatus, hasQuery: boolean): { title: StreamTextKey; meta: StreamTextKey; icon: IconName } {
  if (status === "provider_not_configured") {
    return { title: "feedStateProviderNotConfigured", meta: "providerConfigRequired", icon: "cloud-offline-outline" };
  }

  if (status === "loading") {
    return { title: "feedStateLoading", meta: "realFeedContract", icon: "sync-outline" };
  }

  if (status === "error") {
    return { title: "feedStateError", meta: "retryRealFeedLocked", icon: "warning-outline" };
  }

  if (status === "ready") {
    return { title: "feedStateReady", meta: "realFeedOnly", icon: "checkmark-circle-outline" };
  }

  return { title: hasQuery ? "noResults" : "feedStateEmpty", meta: hasQuery ? "connectLater" : "backendReadyNotConnected", icon: hasQuery ? "search-outline" : "radio-outline" };
}

