function StreamMembershipPanel({
  visible,
  onClose,
  t,
}: {
  visible: boolean;
  onClose: () => void;
  t: (key: StreamTextKey) => string;
}) {
  const [selectedMembershipDraft, setSelectedMembershipDraft] = useState<MembershipControlTileKey | null>(null);
  const selectedMembershipTile = membershipControlTiles.find((tile) => tile.key === selectedMembershipDraft) ?? null;
  const membershipDraftReady = selectedMembershipTile !== null;

  if (!visible) {
    return null;
  }

  return (
    <View style={styles.membershipPanel}>
      <View style={styles.membershipTop}>
        <View>
          <Text style={styles.membershipTitle}>{t("membershipCenter")}</Text>
          <Text style={styles.membershipMeta}>{membershipDraftReady ? "1 Р»РѕРєР°Р»СЊРЅС‹Р№ С‡РµСЂРЅРѕРІРёРє В· РїРѕРґРїРёСЃРєР° Рё РїСЂРѕРІР°Р№РґРµСЂ Р·Р°РєСЂС‹С‚С‹" : t("membershipProviderLater")}</Text>
        </View>
        <Pressable style={styles.creatorModalClose} hitSlop={10} onPress={onClose} accessibilityRole="button" accessibilityLabel="Р—Р°РєСЂС‹С‚СЊ РѕРєРЅРѕ">
          <Ionicons name="close" size={22} color="#FFFFFF" />
        </Pressable>
      </View>

      <View style={styles.membershipNotice}>
        <View style={styles.sourceDot} />
        <Text style={styles.membershipNoticeText} numberOfLines={2}>
          {t("noFakeSubscription")} В· {t("noFakeMember")} В· {t("noFakeCharge")} В· {t("noFakePremiumAccess")}
        </Text>
      </View>

      <View style={[styles.membershipPreview, membershipDraftReady ? styles.membershipPreviewActive : null]} accessibilityState={{ selected: membershipDraftReady }}>
        <Ionicons name={selectedMembershipTile?.icon ?? "people-circle-outline"} size={44} color={membershipDraftReady ? "#09070D" : "#F2C75B"} />
        <Text style={[styles.membershipPreviewTitle, membershipDraftReady ? styles.membershipPreviewTitleActive : null]}>{selectedMembershipTile ? t(selectedMembershipTile.title) : t("fanClub")}</Text>
        <Text style={[styles.membershipPreviewMeta, membershipDraftReady ? styles.membershipPreviewMetaActive : null]}>{membershipDraftReady ? "Р»РѕРєР°Р»СЊРЅС‹Р№ С‡РµСЂРЅРѕРІРёРє РІС‹Р±СЂР°РЅ В· Р±РµР· РѕРїР»Р°С‚С‹" : t("fanClubProviderLater")}</Text>
      </View>

      <View style={styles.membershipGrid}>
        {membershipControlTiles.map((tile) => {
          const active = selectedMembershipDraft === tile.key;
          return (
            <Pressable
              key={tile.key}
              style={[styles.membershipTile, active ? styles.membershipTileActive : null]}
              onPress={() => setSelectedMembershipDraft((current) => current === tile.key ? null : tile.key)}
              hitSlop={8}
              accessibilityRole="button"
              accessibilityLabel={t(tile.title)}
              accessibilityState={{ selected: active }}
            >
              <View style={[styles.membershipTileIcon, active ? styles.membershipTileIconActive : null]}>
                <Ionicons name={tile.icon} size={21} color={active ? "#09070D" : "#F2C75B"} />
              </View>
              <View style={styles.membershipTileText}>
                <Text style={[styles.membershipTileTitle, active ? styles.membershipTileTitleActive : null]} numberOfLines={1}>{t(tile.title)}</Text>
                <Text style={[styles.membershipTileStatus, active ? styles.membershipTileStatusActive : null]} numberOfLines={1}>{t(tile.status)}</Text>
              </View>
            </Pressable>
          );
        })}
      </View>

      <Pressable
        style={[styles.membershipLockedButton, membershipDraftReady ? styles.membershipLockedButtonActive : null]}
        disabled={true}
        hitSlop={8}
        accessibilityRole="button"
        accessibilityState={{ selected: membershipDraftReady, disabled: true }}
        accessibilityLabel={membershipDraftReady ? `${t("joinMembershipLocked")} В· С‡РµСЂРЅРѕРІРёРє Р·Р°РєСЂС‹С‚` : t("joinMembershipLocked")}
      >
        <Text style={[styles.membershipLockedText, membershipDraftReady ? styles.membershipLockedTextActive : null]}>{membershipDraftReady ? `${t("joinMembershipLocked")} В· С‡РµСЂРЅРѕРІРёРє` : t("joinMembershipLocked")}</Text>
      </Pressable>
    </View>
  );
}

