const streamRoomLinkGuardPattern = /(https?:\/\/|www\.|t\.me\/|telegram\.me\/|\b[a-z0-9-]+\.(com|ru|uz|net|org|io)\b)/i;
const streamRoomBlockedKeywordFragments = ["spam", "scam", "casino", "fake", "СЃРїР°Рј", "СЃРєР°Рј", "РєР°Р·РёРЅРѕ", "РјРѕС€РµРЅ"] as const;

function streamRoomHasBlockedLink(text: string): boolean {
  return streamRoomLinkGuardPattern.test(text.trim());
}

function streamRoomHasBlockedKeyword(text: string): boolean {
  const normalized = text.trim().toLowerCase();
  return streamRoomBlockedKeywordFragments.some((fragment) => normalized.includes(fragment));
}

