type TranslationControlTileKey = "captions" | "audio" | "language" | "lock" | "transcript" | "style" | "moderation";

type TranslationControlTile = {
  key: TranslationControlTileKey;
  icon: IconName;
  title: StreamTextKey;
  status: StreamTextKey;
};

const translationControlTiles: TranslationControlTile[] = [
  { key: "captions", icon: "language-outline", title: "liveCaptions", status: "captionsProviderLater" },
  { key: "audio", icon: "mic-outline", title: "audioTranslation", status: "translationProviderLater" },
  { key: "language", icon: "text-outline", title: "captionLanguage", status: "languageProviderLater" },
  { key: "lock", icon: "lock-closed-outline", title: "languageLock", status: "premiumAiRequired" },
  { key: "transcript", icon: "document-text-outline", title: "transcriptArchive", status: "sttProviderLater" },
  { key: "style", icon: "color-palette-outline", title: "captionStyle", status: "captionStyleLocked" },
  { key: "moderation", icon: "shield-checkmark-outline", title: "aiModerationBridge", status: "moderationLater" },
];

function StreamTranslationPanel({
  visible,
  onClose,
  t,
}: {
  visible: boolean;
  onClose: () => void;
  t: (key: StreamTextKey) => string;
}) {
  const [selectedTranslationDraft, setSelectedTranslationDraft] = useState<TranslationControlTileKey | null>(null);
  const selectedTranslationTile = translationControlTiles.find((tile) => tile.key === selectedTranslationDraft) ?? null;
  const translationDraftReady = selectedTranslationTile !== null;

  if (!visible) {
    return null;
  }

  return (
    <View style={styles.translationPanel}>
      <View style={styles.translationTop}>
        <View>
          <Text style={styles.translationTitle}>{t("aiTranslationCenter")}</Text>
          <Text style={styles.translationMeta}>{translationDraftReady ? "1 Р»РѕРєР°Р»СЊРЅС‹Р№ С‡РµСЂРЅРѕРІРёРє В· Premium Рё РїСЂРѕРІР°Р№РґРµСЂ Р·Р°РєСЂС‹С‚С‹" : t("premiumAiRequired")}</Text>
        </View>
        <Pressable style={styles.creatorModalClose} hitSlop={10} onPress={onClose} accessibilityRole="button" accessibilityLabel="Р—Р°РєСЂС‹С‚СЊ AI-РїРµСЂРµРІРѕРґ">
          <Ionicons name="close" size={22} color="#FFFFFF" />
        </Pressable>
      </View>

      <View style={styles.translationNotice}>
        <View style={styles.sourceDot} />
        <Text style={styles.translationNoticeText} numberOfLines={2}>
          {t("noFakeTranslation")} В· {t("noFakeCaptions")} В· {t("noFakeTranscript")} В· {t("noFakeAiAnswer")}
        </Text>
      </View>

      <View style={[styles.translationPreview, translationDraftReady ? styles.translationPreviewActive : null]} accessibilityState={{ selected: translationDraftReady }}>
        <Ionicons name={selectedTranslationTile?.icon ?? "language-outline"} size={44} color={translationDraftReady ? "#09070D" : "#F2C75B"} />
        <Text style={[styles.translationPreviewTitle, translationDraftReady ? styles.translationPreviewTitleActive : null]}>{selectedTranslationTile ? t(selectedTranslationTile.title) : t("subtitlesTranslation")}</Text>
        <Text style={[styles.translationPreviewMeta, translationDraftReady ? styles.translationPreviewMetaActive : null]}>{translationDraftReady ? "Р»РѕРєР°Р»СЊРЅС‹Р№ С‡РµСЂРЅРѕРІРёРє РІС‹Р±СЂР°РЅ В· Р±РµР· РїСЂРѕРІР°Р№РґРµСЂР°" : t("translationProviderLater")}</Text>
      </View>

      <View style={styles.translationGrid}>
        {translationControlTiles.map((tile) => {
          const active = selectedTranslationDraft === tile.key;
          return (
            <Pressable
              key={tile.key}
              style={[styles.translationTile, active ? styles.translationTileActive : null]}
              onPress={() => setSelectedTranslationDraft((current) => current === tile.key ? null : tile.key)}
              accessibilityLabel={t(tile.title)}
              accessibilityState={{ selected: active }}
            >
              <View style={[styles.translationTileIcon, active ? styles.translationTileIconActive : null]}>
                <Ionicons name={tile.icon} size={21} color={active ? "#09070D" : "#F2C75B"} />
              </View>
              <View style={styles.translationTileText}>
                <Text style={[styles.translationTileTitle, active ? styles.translationTileTitleActive : null]} numberOfLines={1}>{t(tile.title)}</Text>
                <Text style={[styles.translationTileStatus, active ? styles.translationTileStatusActive : null]} numberOfLines={1}>{t(tile.status)}</Text>
              </View>
            </Pressable>
          );
        })}
      </View>

      <Pressable
        style={[styles.translationLockedButton, translationDraftReady ? styles.translationLockedButtonActive : null]}
        disabled={true}
        accessibilityState={{ selected: translationDraftReady, disabled: true }}
        accessibilityLabel={translationDraftReady ? `${t("applyTranslationLocked")} В· С‡РµСЂРЅРѕРІРёРє Р·Р°РєСЂС‹С‚` : t("applyTranslationLocked")}
      >
        <Text style={[styles.translationLockedText, translationDraftReady ? styles.translationLockedTextActive : null]}>{translationDraftReady ? `${t("applyTranslationLocked")} В· С‡РµСЂРЅРѕРІРёРє` : t("applyTranslationLocked")}</Text>
      </Pressable>
    </View>
  );
}

type PlaybackControlTileKey = "quality" | "audio" | "fullscreen" | "subtitles" | "center" | "clip" | "report";

type PlaybackControlTile = {
  key: PlaybackControlTileKey;
  icon: IconName;
  title: StreamTextKey;
  status: StreamTextKey;
};

type StreamRoomPlaybackLocalState = {
  qualityPreview: boolean;
  fullscreenPreview: boolean;
  reportDraft: boolean;
};

const playbackControlTiles: PlaybackControlTile[] = [
  { key: "quality", icon: "speedometer-outline", title: "qualityControl", status: "qualityProviderLater" },
  { key: "audio", icon: "volume-high-outline", title: "audioControl", status: "audioProviderLater" },
  { key: "fullscreen", icon: "expand-outline", title: "fullscreenMode", status: "fullscreenLocked" },
  { key: "subtitles", icon: "language-outline", title: "subtitlesTranslation", status: "subtitlesLocked" },
  { key: "center", icon: "radio-outline", title: "playbackCenter", status: "streamConnectionLater" },
  { key: "clip", icon: "cut-outline", title: "createClip", status: "clipProviderLater" },
  { key: "report", icon: "alert-circle-outline", title: "streamReport", status: "moderationLater" },
];

function StreamPlaybackPanel({
  visible,
  onClose,
  onOpenClips,
  onOpenTranslation,
  onTogglePlayback,
  onToggleMuted,
  onToggleQualityPreview,
  onToggleFullscreenPreview,
  onToggleReportDraft,
  playbackState,
  roomIsPlaying,
  roomMuted,
  hostStatus,
  t,
}: {
  visible: boolean;
  onClose: () => void;
  onOpenClips: () => void;
  onOpenTranslation: () => void;
  onTogglePlayback: () => void;
  onToggleMuted: () => void;
  onToggleQualityPreview: () => void;
  onToggleFullscreenPreview: () => void;
  onToggleReportDraft: () => void;
  playbackState: StreamRoomPlaybackLocalState;
  roomIsPlaying: boolean;
  roomMuted: boolean;
  hostStatus: StreamRoomHostLifecycleStatus;
  t: (key: StreamTextKey) => string;
}) {
  if (!visible) {
    return null;
  }

  const playbackEnded = hostStatus === "ended";
  const playbackLive = hostStatus === "live" && roomIsPlaying;
  const playbackPaused = hostStatus === "paused" || !playbackLive;
  const playbackActionAllowed = playbackLive && !playbackEnded;
  const playbackReportAllowed = !playbackEnded;
  const playbackBlockedReason = playbackEnded ? "СЌС„РёСЂ Р·Р°РІРµСЂС€С‘РЅ" : hostStatus === "live" ? "РІРєР»СЋС‡РёС‚Рµ РїСЂРѕСЃРјРѕС‚СЂ" : hostStatus === "paused" ? "СЌС„РёСЂ РЅР° РїР°СѓР·Рµ" : "СЌС„РёСЂ РµС‰С‘ РЅРµ Р·Р°РїСѓС‰РµРЅ";
  const localPlaybackReady = playbackState.qualityPreview || playbackState.fullscreenPreview || playbackState.reportDraft || roomMuted || playbackActionAllowed;
  const localActionCount = [playbackState.qualityPreview, playbackState.fullscreenPreview, playbackState.reportDraft, roomMuted].filter(Boolean).length;
  const previewIcon: IconName = playbackEnded ? "stop-circle-outline" : playbackPaused ? "play-circle-outline" : "pause-circle-outline";
  const previewTitle = playbackEnded ? "СЌС„РёСЂ Р·Р°РІРµСЂС€С‘РЅ" : !playbackActionAllowed ? "РїСЂРѕСЃРјРѕС‚СЂ Р·Р°Р±Р»РѕРєРёСЂРѕРІР°РЅ" : playbackLive ? "СЌС„РёСЂ РёРґС‘С‚" : "Р»РѕРєР°Р»СЊРЅС‹Р№ РїСЂРѕСЃРјРѕС‚СЂ";
  const previewMeta = !playbackActionAllowed ? `${playbackBlockedReason} В· ${localActionCount}/4 Р»РѕРєР°Р»СЊРЅС‹С… РґРµР№СЃС‚РІРёСЏ` : `${localActionCount}/4 Р»РѕРєР°Р»СЊРЅС‹С… РґРµР№СЃС‚РІРёСЏ В· ${roomMuted ? "Р·РІСѓРє РІС‹РєР»СЋС‡РµРЅ" : "Р·РІСѓРє РѕС‚РєСЂС‹С‚"}`;

  const isTileActive = (key: PlaybackControlTileKey) => {
    if (key === "quality") return playbackState.qualityPreview;
    if (key === "audio") return roomMuted;
    if (key === "fullscreen") return playbackState.fullscreenPreview;
    if (key === "center") return playbackActionAllowed;
    if (key === "report") return playbackState.reportDraft;
    return false;
  };

  const isTileDisabled = (key: PlaybackControlTileKey) => {
    if (key === "report") return !playbackReportAllowed;
    return !playbackActionAllowed;
  };

  const handleTilePress = (key: PlaybackControlTileKey) => {
    if (isTileDisabled(key)) {
      return;
    }
    if (key === "quality") {
      onToggleQualityPreview();
      return;
    }
    if (key === "audio") {
      onToggleMuted();
      return;
    }
    if (key === "fullscreen") {
      onToggleFullscreenPreview();
      return;
    }
    if (key === "subtitles") {
      onOpenTranslation();
      return;
    }
    if (key === "center") {
      onTogglePlayback();
      return;
    }
    if (key === "clip") {
      onOpenClips();
      return;
    }
    if (key === "report") {
      onToggleReportDraft();
    }
  };

  return (
    <View style={styles.playbackPanel}>
      <View style={styles.playbackTop}>
        <View>
          <Text style={styles.playbackTitle}>{t("playbackCenter")}</Text>
          <Text style={styles.playbackMeta}>{localActionCount}/4 Р»РѕРєР°Р»СЊРЅС‹С… РґРµР№СЃС‚РІРёСЏ РіРѕС‚РѕРІРѕ</Text>
        </View>
        <Pressable style={styles.creatorModalClose} hitSlop={10} onPress={onClose} accessibilityRole="button" accessibilityLabel="Р—Р°РєСЂС‹С‚СЊ РѕРєРЅРѕ">
          <Ionicons name="close" size={22} color="#FFFFFF" />
        </Pressable>
      </View>

      <View style={styles.playbackNotice}>
        <View style={styles.sourceDot} />
        <Text style={styles.playbackNoticeText} numberOfLines={2}>
          {t("noFakePlayback")} В· {t("noFakeQuality")} В· {t("noFakeSubtitles")}
        </Text>
      </View>

      <View style={[styles.playbackPreview, localPlaybackReady ? styles.playbackPreviewActive : null, playbackEnded ? styles.playbackPreviewEnded : null]} accessibilityState={{ selected: localPlaybackReady, disabled: playbackEnded }}>
        <Ionicons name={previewIcon} size={48} color={localPlaybackReady && !playbackEnded ? "#09070D" : "#F2C75B"} />
        <Text style={[styles.playbackPreviewTitle, localPlaybackReady && !playbackEnded ? styles.playbackPreviewTitleActive : null]}>{previewTitle}</Text>
        <Text style={[styles.playbackPreviewMeta, localPlaybackReady && !playbackEnded ? styles.playbackPreviewMetaActive : null]}>{previewMeta}</Text>
      </View>

      <View style={styles.playbackStatusRow}>
        <View style={[styles.playbackStatusPill, roomIsPlaying && !playbackEnded ? styles.playbackStatusPillReady : null]} accessibilityState={{ selected: roomIsPlaying && !playbackEnded }}>
          <Text style={[styles.playbackStatusText, roomIsPlaying && !playbackEnded ? styles.playbackStatusTextReady : null]}>{roomIsPlaying && !playbackEnded ? "РёРґС‘С‚" : playbackEnded ? "СЃС‚РѕРї" : "РїР°СѓР·Р°"}</Text>
        </View>
        <View style={[styles.playbackStatusPill, roomMuted ? styles.playbackStatusPillReady : null]} accessibilityState={{ selected: roomMuted }}>
          <Text style={[styles.playbackStatusText, roomMuted ? styles.playbackStatusTextReady : null]}>{roomMuted ? "mute" : "Р·РІСѓРє"}</Text>
        </View>
        <View style={[styles.playbackStatusPill, playbackState.qualityPreview ? styles.playbackStatusPillReady : null]} accessibilityState={{ selected: playbackState.qualityPreview }}>
          <Text style={[styles.playbackStatusText, playbackState.qualityPreview ? styles.playbackStatusTextReady : null]}>{playbackState.qualityPreview ? "РєР°С‡РµСЃС‚РІРѕ" : "auto"}</Text>
        </View>
        <View style={[styles.playbackStatusPill, playbackState.reportDraft ? styles.playbackStatusPillReady : null]} accessibilityState={{ selected: playbackState.reportDraft }}>
          <Text style={[styles.playbackStatusText, playbackState.reportDraft ? styles.playbackStatusTextReady : null]}>{playbackState.reportDraft ? "Р¶Р°Р»РѕР±Р°" : "С‡РёСЃС‚Рѕ"}</Text>
        </View>
      </View>

      <View style={styles.playbackGrid}>
        {playbackControlTiles.map((tile) => {
          const active = isTileActive(tile.key);
          const disabled = isTileDisabled(tile.key);
          const tileStatus = disabled ? playbackBlockedReason : t(tile.status);
          return (
            <Pressable
              key={tile.key}
              style={[styles.playbackTile, active ? styles.playbackTileActive : null, disabled ? styles.playbackTileDisabled : null]}
              onPress={() => handleTilePress(tile.key)}
              disabled={disabled}
              accessibilityState={{ selected: active, disabled }}
            >
              <View style={[styles.playbackTileIcon, active ? styles.playbackTileIconActive : null, disabled ? styles.playbackTileDisabled : null]}>
                <Ionicons name={tile.icon} size={21} color={active ? "#09070D" : disabled ? "#7E7488" : "#F2C75B"} />
              </View>
              <View style={styles.playbackTileText}>
                <Text style={[styles.playbackTileTitle, active ? styles.playbackTileTitleActive : null]} numberOfLines={1}>{t(tile.title)}</Text>
                <Text style={[styles.playbackTileStatus, active ? styles.playbackTileStatusActive : null]} numberOfLines={1}>{tileStatus}</Text>
              </View>
            </Pressable>
          );
        })}
      </View>

      <Pressable
        style={styles.playbackLockedButton}
        disabled={true}
        accessibilityState={{ disabled: true }}
        accessibilityLabel={`${t("applyPlaybackLocked")} В· locked`}
      >
        <Text style={styles.playbackLockedText}>{t("applyPlaybackLocked")}</Text>
      </Pressable>
    </View>
  );
}

