function ScheduleActionModal({
  action,
  onClose,
  t,
}: {
  action: ScheduleAction | null;
  onClose: () => void;
  t: (key: StreamTextKey) => string;
}) {
  if (!action) {
    return null;
  }

  const config = scheduleActionConfig[action];
  const { height: scheduleWindowHeight, width: scheduleWindowWidth } = useWindowDimensions();
  const scheduleInsets = useSafeAreaInsets();
  const scheduleCompactPhone = scheduleWindowWidth < 380 || scheduleWindowHeight < 720;
  const scheduleSheetMaxHeight = Math.max(360, scheduleWindowHeight - scheduleInsets.top - scheduleInsets.bottom - 48);
  const scheduleSheetBottomPadding = Math.max(18, scheduleInsets.bottom + 16);

  return (
    <Modal visible={Boolean(action)} transparent animationType="fade" onRequestClose={onClose}>
      <Pressable style={styles.modalBackdrop} onPress={onClose}>
        <Pressable
          style={[styles.scheduleModalSheet, { maxHeight: scheduleSheetMaxHeight, paddingBottom: scheduleSheetBottomPadding }, scheduleCompactPhone ? styles.scheduleModalSheetCompact : null]}
          onPressIn={(event) => event.stopPropagation()}
          onPress={(event) => event.stopPropagation()}
        >
          <View style={styles.scheduleModalTop}>
            <View style={styles.scheduleModalIcon}>
              <Ionicons name={config.icon} size={25} color="#F2C75B" />
            </View>
            <View style={styles.scheduleModalTitleWrap}>
              <Text style={styles.scheduleModalTitle} numberOfLines={1}>{t(config.title)}</Text>
              <Text style={styles.scheduleModalMeta} numberOfLines={1}>{t(config.status)}</Text>
            </View>
            <Pressable style={styles.creatorModalClose} hitSlop={10} onPress={onClose} accessibilityRole="button" accessibilityLabel="Р—Р°РєСЂС‹С‚СЊ РѕРєРЅРѕ">
              <Ionicons name="close" size={22} color="#FFFFFF" />
            </Pressable>
          </View>

          <ScrollView
            style={styles.scheduleModalBodyScroll}
            contentContainerStyle={[styles.scheduleModalBodyContent, { paddingBottom: Math.max(6, scheduleSheetBottomPadding - 12) }, scheduleCompactPhone ? styles.scheduleModalBodyContentCompact : null]}
            showsVerticalScrollIndicator={false}
            nestedScrollEnabled={true}
            overScrollMode="never"
            keyboardShouldPersistTaps="handled"
          >
            <View style={styles.scheduleModalNotice}>
              <View style={styles.sourceDot} />
              <Text style={styles.scheduleModalNoticeText} numberOfLines={2}>
                {t("lockedUntilProvider")} В· {t("serverSyncLater")} В· {t("realEventLater")}
              </Text>
            </View>

            <View style={[styles.scheduleModalGrid, scheduleCompactPhone ? styles.scheduleModalGridCompact : null]}>
              <View style={[styles.scheduleModalTile, scheduleCompactPhone ? styles.scheduleModalTileCompact : null]}>
                <Ionicons name="time-outline" size={scheduleCompactPhone ? 19 : 21} color="#F2C75B" />
                <Text style={styles.scheduleModalTileTitle} numberOfLines={1}>{t("scheduleSlot")}</Text>
                <Text style={styles.scheduleModalTileMeta} numberOfLines={1}>{t("waitingForProvider")}</Text>
              </View>
              <View style={[styles.scheduleModalTile, scheduleCompactPhone ? styles.scheduleModalTileCompact : null]}>
                <Ionicons name="notifications-outline" size={scheduleCompactPhone ? 19 : 21} color="#F2C75B" />
                <Text style={styles.scheduleModalTileTitle} numberOfLines={1}>{t("reminderLocked")}</Text>
                <Text style={styles.scheduleModalTileMeta} numberOfLines={1}>{t("reminderProviderLater")}</Text>
              </View>
              <View style={[styles.scheduleModalTile, scheduleCompactPhone ? styles.scheduleModalTileCompact : null]}>
                <Ionicons name="cloud-outline" size={scheduleCompactPhone ? 19 : 21} color="#F2C75B" />
                <Text style={styles.scheduleModalTileTitle} numberOfLines={1}>{t("serverSyncLater")}</Text>
                <Text style={styles.scheduleModalTileMeta} numberOfLines={1}>{t("providerLater")}</Text>
              </View>
            </View>

            <Pressable
              style={[styles.scheduleSaveLockedButton, scheduleCompactPhone ? styles.scheduleSaveLockedButtonCompact : null]}
              hitSlop={{ top: 6, bottom: 6, left: 4, right: 4 }}
              accessibilityRole="button"
              accessibilityState={{ disabled: true }}
              accessibilityLabel={t("saveReminderLocked")}
            >
              <Text style={styles.scheduleSaveLockedText} numberOfLines={1}>{t("saveReminderLocked")}</Text>
            </Pressable>
          </ScrollView>
        </Pressable>
      </Pressable>
    </Modal>
  );
}

