  const studioCompactPhone = studioWindowHeight < 720;
  const studioVeryCompactPhone = studioWindowHeight < 640;
  const studioSafeBottom = Math.max(0, studioInsets.bottom);
  const studioSheetMaxHeight = Math.max(420, Math.floor(studioWindowHeight * 0.88) - Math.min(28, studioSafeBottom));
