type LiveLaunchReadinessTile = {
  icon: IconName;
  title: StreamTextKey;
  status: StreamTextKey;
};

function buildLiveLaunchReadinessTiles({
  selectedMode,
  draftState,
  cameraPermissionReady,
  cameraGranted,
  microphonePermissionReady,
  microphoneGranted,
}: {
  selectedMode: LiveMode;
  draftState: PreLiveDraftState;
  cameraPermissionReady: boolean;
  cameraGranted: boolean;
  microphonePermissionReady: boolean;
  microphoneGranted: boolean;
}): LiveLaunchReadinessTile[] {
  const draftTiles: LiveLaunchReadinessTile[] = [
    { icon: draftState.titleReady ? "checkmark-circle-outline" : "create-outline", title: "streamTitle", status: draftState.titleReady ? "streamTitleReady" : "streamTitleRequired" },
    { icon: "pricetag-outline", title: "streamTopic", status: draftState.topicReady ? "streamTopic" : "streamTopicOptional" },
    { icon: "document-text-outline", title: "streamDescription", status: draftState.descriptionReady ? "streamDescription" : "streamDescriptionOptional" },
    { icon: "eye-outline", title: "streamVisibility", status: draftState.visibilityReady ? "visibilityReady" : "audienceGateLocked" },
  ];

  const baseTiles: LiveLaunchReadinessTile[] = [
    { icon: cameraGranted ? "checkmark-circle-outline" : "camera-outline", title: "cameraPermission", status: !cameraPermissionReady ? "cameraPermissionOpening" : cameraGranted ? "cameraPermissionGranted" : "permissionRequired" },
    { icon: microphoneGranted ? "checkmark-circle-outline" : "mic-outline", title: "microphonePermission", status: !microphonePermissionReady ? "micPermissionOpening" : microphoneGranted ? "micPermissionGranted" : "micPermissionNeeded" },
    { icon: "radio-outline", title: "streamIngest", status: "ingestNotReady" },
    { icon: "link-outline", title: "rtmpEndpoint", status: "endpointNotReady" },
    { icon: "cloud-offline-outline", title: "liveProviderBinding", status: "providerNotConfigured" },
    { icon: "shield-checkmark-outline", title: "moderationGate", status: "policyReviewRequired" },
    { icon: "finger-print-outline", title: "agePolicyGate", status: "policyReviewRequired" },
    { icon: "pulse-outline", title: "networkQualityGate", status: "networkCheckRequired" },
  ];

  const selectedModeTiles: LiveLaunchReadinessTile[] = liveModeSetupItems[selectedMode].slice(0, 3).map((item) => ({
    icon: item.icon,
    title: item.title,
    status: item.status,
  }));

  return [...draftTiles, ...baseTiles, ...selectedModeTiles];
}

function LiveLaunchReadinessPanel({
  visible,
  selectedMode,
  selectedModeLabel,
  draftState,
  cameraPermissionReady,
  cameraGranted,
  microphonePermissionReady,
  microphoneGranted,
  onClose,
  t,
}: {
  visible: boolean;
  selectedMode: LiveMode;
  selectedModeLabel: StreamTextKey;
  draftState: PreLiveDraftState;
  cameraPermissionReady: boolean;
  cameraGranted: boolean;
  microphonePermissionReady: boolean;
  microphoneGranted: boolean;
  onClose: () => void;
  t: (key: StreamTextKey) => string;
}) {
  const [readinessDetail, setReadinessDetail] = useState<LiveLaunchReadinessTile | null>(null);
  const [blockedReasonOpen, setBlockedReasonOpen] = useState(false);
  const { height: launchWindowHeight } = useWindowDimensions();
  const launchInsets = useSafeAreaInsets();
  const launchSheetMaxHeight = Math.max(420, launchWindowHeight - launchInsets.top - launchInsets.bottom - 50);
  const launchSheetBottomPadding = Math.max(18, launchInsets.bottom + 16);
  const launchScrollMaxHeight = Math.max(176, launchSheetMaxHeight - 306);

  if (!visible) {
    return null;
  }

  const devicePermissionsReady = cameraPermissionReady && cameraGranted && microphonePermissionReady && microphoneGranted;
  const liveLaunchReadinessTiles = buildLiveLaunchReadinessTiles({
    selectedMode,
    draftState,
    cameraPermissionReady,
    cameraGranted,
    microphonePermissionReady,
    microphoneGranted,
  });

  return (
    <>
      <Modal visible={visible} transparent animationType="fade" onRequestClose={onClose}>
      <Pressable style={styles.modalBackdrop} onPress={onClose}>
        <Pressable
          style={[styles.liveLaunchSheet, { maxHeight: launchSheetMaxHeight, paddingBottom: launchSheetBottomPadding }]}
          onPressIn={(event) => event.stopPropagation()}
          onTouchStart={(event) => event.stopPropagation()}
          onPress={(event) => event.stopPropagation()}
        >
          <View style={styles.liveLaunchTop}>
            <View style={styles.liveLaunchIcon}>
              <Ionicons name="radio-outline" size={25} color="#F2C75B" />
            </View>
            <View style={styles.liveLaunchTitleWrap}>
              <Text style={styles.liveLaunchTitle} numberOfLines={1}>{t("liveLaunchGate")}</Text>
              <Text style={styles.liveLaunchMeta} numberOfLines={1}>{devicePermissionsReady ? t("devicePermissionsReady") : t("devicePermissionRequired")}</Text>
            </View>
            <Pressable style={styles.creatorModalClose} hitSlop={10} onPress={onClose} accessibilityRole="button" accessibilityLabel="Р—Р°РєСЂС‹С‚СЊ РѕРєРЅРѕ">
              <Ionicons name="close" size={22} color="#FFFFFF" />
            </Pressable>
          </View>

          <View style={styles.liveLaunchNotice}>
            <View style={styles.sourceDot} />
            <Text style={styles.liveLaunchNoticeText} numberOfLines={2}>
              {t("preLiveDraftValidation")} В· {t("localDraftOnly")} В· {t("noFakeDraftSave")} В· {t("noFakeDraftPublish")}
            </Text>
          </View>

          <View style={styles.liveLaunchPreview}>
            <Ionicons name="cloud-offline-outline" size={46} color="#F2C75B" />
            <Text style={styles.liveLaunchPreviewTitle}>{t("modeSpecificReadiness")}</Text>
            <Text style={styles.liveLaunchPreviewMeta}>{draftState.titleReady ? t("draftReadyButLaunchBlocked") : t("fillStreamInfoFirst")}: {t(selectedModeLabel)}</Text>
          </View>

          <ScrollView
            style={[styles.liveLaunchScroll, { maxHeight: launchScrollMaxHeight }]}
            contentContainerStyle={styles.liveLaunchGrid}
            showsVerticalScrollIndicator={false}
            nestedScrollEnabled
            overScrollMode="never"
          >
            {liveLaunchReadinessTiles.map((tile) => (
              <Pressable
                key={`${tile.title}-${tile.status}`}
                style={styles.liveLaunchTile}
                onPress={() => setReadinessDetail(tile)}
                accessibilityLabel={t("openReadinessDetail")}
              >
                <View style={styles.liveLaunchTileIcon}>
                  <Ionicons name={tile.icon} size={21} color="#F2C75B" />
                </View>
                <View style={styles.liveLaunchTileText}>
                  <Text style={styles.liveLaunchTileTitle} numberOfLines={1}>{t(tile.title)}</Text>
                  <Text style={styles.liveLaunchTileStatus} numberOfLines={1}>{t(tile.status)}</Text>
                </View>
              </Pressable>
            ))}
          </ScrollView>

          <Pressable style={styles.liveLaunchBlockedButton} onPress={() => setBlockedReasonOpen(true)} accessibilityLabel={t("launchBlockedReason")}>
            <Text style={styles.liveLaunchBlockedText}>{t("launchBlockedReason")}</Text>
          </Pressable>
        </Pressable>
      </Pressable>
      </Modal>

      <LiveLaunchReadinessDetailPanel
        detail={readinessDetail}
        selectedModeLabel={selectedModeLabel}
        onClose={() => setReadinessDetail(null)}
        t={t}
      />

      <LiveLaunchBlockedReasonPanel
        visible={blockedReasonOpen}
        selectedModeLabel={selectedModeLabel}
        onClose={() => setBlockedReasonOpen(false)}
        t={t}
      />
    </>
  );
}

