function PreLiveCameraPreview({
  facing,
  microphoneMuted,
  microphoneGranted,
  microphonePermissionReady,
  onCameraPermissionChange,
  onOpenMediaSource,
  statusBottomOffset,
  gateBottomOffset,
  compact,
  t,
}: {
  facing: PreLiveCameraFacing;
  microphoneMuted: boolean;
  microphoneGranted: boolean;
  microphonePermissionReady: boolean;
  onCameraPermissionChange: (state: PreLivePermissionState) => void;
  onOpenMediaSource: () => void;
  statusBottomOffset: number;
  gateBottomOffset: number;
  compact: boolean;
  t: (key: StreamTextKey) => string;
}) {
  const [permission, requestPermission] = useCameraPermissions();

  useEffect(() => {
    if (!permission) {
      void requestPermission();
    }
  }, [permission, requestPermission]);

  const granted = Boolean(permission?.granted);
  const waiting = !permission;

  useEffect(() => {
    onCameraPermissionChange({ ready: !waiting, granted });
  }, [granted, waiting, onCameraPermissionChange]);

  return (
    <Pressable style={styles.cameraPreview} onPress={onOpenMediaSource} accessibilityLabel={t("openMediaSource")}>
      {granted ? (
        <CameraView style={styles.liveCameraFill} facing={facing} />
      ) : (
        <View style={styles.cameraPermissionState}>
          <View style={styles.cameraLens}>
            <Ionicons name="camera-outline" size={58} color="#F2C75B" />
          </View>
          <Text style={styles.cameraPreviewText}>{waiting ? t("cameraOpening") : t("cameraPermissionNeeded")}</Text>
          <Text style={styles.cameraPreviewSubText}>{t("realCameraOnly")}</Text>
        </View>
      )}

      <LinearGradient
        pointerEvents="none"
        colors={["rgba(0,0,0,0.35)", "rgba(0,0,0,0.04)", "rgba(0,0,0,0.58)"]}
        style={styles.liveCameraOverlay}
      />

      <View pointerEvents="none" style={[styles.preLiveCameraStatusBar, { bottom: statusBottomOffset }, compact ? styles.preLiveCameraStatusBarCompact : null]}>
        <View style={[styles.preLiveCameraStatusPill, !granted ? styles.preLiveCameraStatusPillWarning : null]}>
          <Ionicons name={granted ? "checkmark-circle-outline" : "camera-outline"} size={14} color={granted ? "#86EFAC" : "#F2C75B"} />
          <Text style={styles.preLiveCameraStatusText} numberOfLines={1}>
            {facing === "back" ? t("backCamera") : t("frontCamera")} В· {granted ? t("readyShort") : t("neededShort")}
          </Text>
        </View>
        <View style={[styles.preLiveCameraStatusPill, (!microphoneGranted || microphoneMuted) ? styles.preLiveCameraStatusPillWarning : null]}>
          <Ionicons name={!microphoneGranted || microphoneMuted ? "mic-off-outline" : "mic-outline"} size={14} color={!microphoneGranted || microphoneMuted ? "#F2C75B" : "#86EFAC"} />
          <Text style={styles.preLiveCameraStatusText} numberOfLines={1}>
            {t("microphone")} В· {microphonePermissionReady && microphoneGranted && !microphoneMuted ? t("readyShort") : t("neededShort")}
          </Text>
        </View>
      </View>

      <View pointerEvents="none" style={[styles.cameraPreviewGate, { bottom: gateBottomOffset }, compact ? styles.cameraPreviewGateCompact : null]}>
        <Ionicons name="lock-closed-outline" size={13} color="#F2C75B" />
        <Text style={styles.cameraPreviewGateText} numberOfLines={1}>{t("noFakeOnAir")} В· {t("realCameraOnly")}</Text>
      </View>

    </Pressable>
  );
}

function PreLiveModeSelector({
  mode,
  bottomOffset,
  compact,
  onChangeMode,
  onOpenModeSetup,
  t,
}: {
  mode: LiveMode;
  bottomOffset: number;
  compact: boolean;
  onChangeMode: (nextMode: LiveMode) => void;
  onOpenModeSetup: () => void;
  t: (key: StreamTextKey) => string;
}) {
  const activeMode = liveModes.find((item) => item.id === mode) ?? liveModes[0];

  return (
    <View
      style={[styles.preLiveModeDock, { bottom: bottomOffset }, compact ? styles.preLiveModeDockCompact : null]}
      onStartShouldSetResponder={() => true}
    >
      <View style={styles.preLiveModeDockHeader}>
        <Text style={styles.preLiveModeDockTitle} numberOfLines={1}>{t("activeLiveMode")}: {t(activeMode.shortLabel)}</Text>
        <Text style={styles.preLiveModeDockHint} numberOfLines={1}>{mode === "businessLive" ? t("businessModeLockedShopping") : t("tapActiveModeSetup")}</Text>
      </View>
      <ScrollView
        horizontal
        showsHorizontalScrollIndicator={false}
        contentContainerStyle={styles.preLiveModePagerContent}
        nestedScrollEnabled
        overScrollMode="never"
      >
        {liveModes.map((item) => {
          const active = item.id === mode;
          return (
            <Pressable
              key={item.id}
              style={[styles.preLiveModePagerCard, active ? styles.preLiveModePagerCardActive : null]}
              onPress={() => {
                if (active) {
                  onOpenModeSetup();
                  return;
                }
                onChangeMode(item.id);
              }}
              accessibilityLabel={`${t("activeLiveMode")} ${t(item.label)}`}
            >
              <Ionicons name={item.icon} size={16} color={active ? "#09070D" : "#FFFFFF"} />
              <Text style={[styles.preLiveModePagerTitle, active ? styles.preLiveModePagerTitleActive : null]} numberOfLines={1}>{t(item.shortLabel)}</Text>
            </Pressable>
          );
        })}
      </ScrollView>
    </View>
  );
}

