function StreamCreatorVerificationPanel({
  visible,
  onClose,
  t,
}: {
  visible: boolean;
  onClose: () => void;
  t: (key: StreamTextKey) => string;
}) {
  const [selectedVerificationDraft, setSelectedVerificationDraft] = useState<StreamTextKey | null>(null);

  useEffect(() => {
    setSelectedVerificationDraft(null);
  }, [visible]);

  const closeVerificationDraft = () => {
    setSelectedVerificationDraft(null);
    onClose();
  };

  const selectedVerificationTile = verificationControlTiles.find((tile) => tile.title === selectedVerificationDraft && tile.draftSupported) ?? null;
  const verificationDraftReady = selectedVerificationTile !== null;

  if (!visible) {
    return null;
  }

  return (
    <Modal visible={visible} transparent animationType="fade" onRequestClose={closeVerificationDraft}>
      <Pressable style={styles.modalBackdrop} onPress={closeVerificationDraft}>
        <Pressable style={styles.creatorVerificationSheet} onPressIn={(event) => event.stopPropagation()}
          onPress={(event) => event.stopPropagation()}>
          <View style={styles.creatorVerificationTop}>
            <View style={styles.creatorVerificationIcon}>
              <Ionicons name="shield-checkmark-outline" size={25} color="#F2C75B" />
            </View>
            <View style={styles.creatorVerificationTitleWrap}>
              <Text style={styles.creatorVerificationTitle} numberOfLines={1}>{t("creatorVerification")}</Text>
              <Text style={styles.creatorVerificationMeta} numberOfLines={1}>{verificationDraftReady ? `${t(selectedVerificationTile.title)} В· С‡РµСЂРЅРѕРІРёРє Р·Р°РєСЂС‹С‚` : t("adminReviewLater")}</Text>
            </View>
            <Pressable style={styles.creatorModalClose} hitSlop={10} onPress={closeVerificationDraft} accessibilityRole="button" accessibilityLabel="Р—Р°РєСЂС‹С‚СЊ РІРµСЂРёС„РёРєР°С†РёСЋ">
              <Ionicons name="close" size={22} color="#FFFFFF" />
            </Pressable>
          </View>

          <View style={[styles.creatorVerificationNotice, verificationDraftReady ? styles.creatorVerificationNoticeActive : null]} accessibilityState={{ selected: verificationDraftReady }}>
            <View style={styles.sourceDot} />
            <Text style={[styles.creatorVerificationNoticeText, verificationDraftReady ? styles.creatorVerificationNoticeTextActive : null]} numberOfLines={2}>
              {t("noFakeApproval")} В· {t("noFakeVerification")} В· {t("noFakeDocuments")} В· {t("noFakeAdminDecision")} В· {verificationDraftReady ? "Р»РѕРєР°Р»СЊРЅС‹Р№ С‡РµСЂРЅРѕРІРёРє" : t("noFakeOfficialBadge")}
            </Text>
          </View>

          <View style={[styles.creatorVerificationPreview, verificationDraftReady ? styles.creatorVerificationPreviewActive : null]} accessibilityState={{ selected: verificationDraftReady }}>
            <Ionicons name={selectedVerificationTile?.icon ?? "ribbon-outline"} size={44} color={verificationDraftReady ? "#09070D" : "#F2C75B"} />
            <Text style={[styles.creatorVerificationPreviewTitle, verificationDraftReady ? styles.creatorVerificationPreviewTitleActive : null]}>{selectedVerificationTile ? t(selectedVerificationTile.title) : t("officialBadgeReview")}</Text>
            <Text style={[styles.creatorVerificationPreviewMeta, verificationDraftReady ? styles.creatorVerificationPreviewMetaActive : null]}>{selectedVerificationTile ? `${t(selectedVerificationTile.status)} В· Р»РѕРєР°Р»СЊРЅС‹Р№ С‡РµСЂРЅРѕРІРёРє` : t("verificationProviderLater")}</Text>
          </View>

          <View style={styles.creatorVerificationGrid}>
            {verificationControlTiles.map((tile) => {
              const locked = !tile.draftSupported;
              const active = !locked && selectedVerificationDraft === tile.title;
              return (
                <Pressable
                  key={`${tile.title}-${tile.status}`}
                  style={[styles.creatorVerificationTile, active ? styles.creatorVerificationTileActive : null, locked ? styles.creatorVerificationTileLocked : null]}
                  onPress={() => {
                    if (locked) {
                      return;
                    }
                    setSelectedVerificationDraft((current) => current === tile.title ? null : tile.title);
                  }}
                  disabled={locked}
                  accessibilityState={{ selected: active, disabled: locked }}
                  accessibilityLabel={`${t(tile.title)} В· ${locked ? t("providerNotConfigured") : active ? "Р»РѕРєР°Р»СЊРЅС‹Р№ С‡РµСЂРЅРѕРІРёРє" : t(tile.status)}`}
                >
                  <View style={[styles.creatorVerificationTileIcon, active ? styles.creatorVerificationTileIconActive : null, locked ? styles.creatorVerificationTileIconLocked : null]}>
                    <Ionicons name={locked ? "lock-closed-outline" : tile.icon} size={21} color={active ? "#09070D" : locked ? "#8D8796" : "#F2C75B"} />
                  </View>
                  <View style={styles.creatorVerificationTileText}>
                    <Text style={[styles.creatorVerificationTileTitle, active ? styles.creatorVerificationTileTitleActive : null, locked ? styles.creatorVerificationTileTitleLocked : null]} numberOfLines={1}>{t(tile.title)}</Text>
                    <Text style={[styles.creatorVerificationTileStatus, active ? styles.creatorVerificationTileStatusActive : null, locked ? styles.creatorVerificationTileStatusLocked : null]} numberOfLines={1}>{locked ? `${t(tile.status)} В· ${t("providerNotConfigured")}` : active ? `${t(tile.status)} В· Р»РѕРєР°Р»СЊРЅС‹Р№ С‡РµСЂРЅРѕРІРёРє` : t(tile.status)}</Text>
                  </View>
                </Pressable>
              );
            })}
          </View>

          <Pressable
            style={[styles.creatorVerificationLockedButton, verificationDraftReady ? styles.creatorVerificationLockedButtonActive : null]}
            disabled={true}
            accessibilityState={{ selected: verificationDraftReady, disabled: true }}
            accessibilityLabel={verificationDraftReady ? `${t("submitVerificationLocked")} В· С‡РµСЂРЅРѕРІРёРє Р·Р°РєСЂС‹С‚` : t("submitVerificationLocked")}
          >
            <Text style={[styles.creatorVerificationLockedText, verificationDraftReady ? styles.creatorVerificationLockedTextActive : null]}>{verificationDraftReady ? `${t("submitVerificationLocked")} В· С‡РµСЂРЅРѕРІРёРє` : t("submitVerificationLocked")}</Text>
          </Pressable>
        </Pressable>
      </Pressable>
    </Modal>
  );
}

function CreatorRegistrationModal({
  visible,
  tile,
  onClose,
  onOpenVerification,
  t,
}: {
  visible: boolean;
  tile: CreatorTile | null;
  onClose: () => void;
  onOpenVerification: () => void;
  t: (key: StreamTextKey) => string;
}) {
  const [selectedRegistrationDraft, setSelectedRegistrationDraft] = useState<StreamTextKey | null>(null);

  useEffect(() => {
    setSelectedRegistrationDraft(null);
  }, [visible, tile?.title, tile?.action]);

  const closeRegistrationDraft = () => {
    setSelectedRegistrationDraft(null);
    onClose();
  };

  if (!tile) {
    return null;
  }

  const showOfficialSteps = tile.action === "official" || tile.action === "setup" || tile.action === "documents";
  const selectedRegistrationStep = showOfficialSteps
    ? officialRegistrationSteps.find((step) => step.title === selectedRegistrationDraft && step.draftSupported) ?? null
    : null;
  const registrationDraftReady = selectedRegistrationStep !== null;
  const openVerificationDraft = () => {
    if (!registrationDraftReady) {
      return;
    }
    setSelectedRegistrationDraft(null);
    onOpenVerification();
  };

  return (
    <Modal visible={visible} transparent animationType="fade" onRequestClose={closeRegistrationDraft}>
      <Pressable style={styles.modalBackdrop} onPress={closeRegistrationDraft}>
        <Pressable style={styles.creatorModalSheet} onPressIn={(event) => event.stopPropagation()}
          onPress={(event) => event.stopPropagation()}>
          <View style={styles.creatorModalTop}>
            <View style={styles.creatorIconBox}>
              <Ionicons name={tile.icon} size={25} color="#F2C75B" />
            </View>
            <View style={styles.creatorModalTitleWrap}>
              <Text style={styles.creatorModalTitle} numberOfLines={1}>{t(tile.title)}</Text>
              <Text style={styles.creatorModalMeta} numberOfLines={1}>{t(tile.status)}</Text>
            </View>
            <Pressable style={styles.creatorModalClose} hitSlop={10} onPress={closeRegistrationDraft} accessibilityRole="button" accessibilityLabel="Р—Р°РєСЂС‹С‚СЊ СЂРµРіРёСЃС‚СЂР°С†РёСЋ">
              <Ionicons name="close" size={22} color="#FFFFFF" />
            </Pressable>
          </View>

          <View style={[styles.creatorModalSafety, registrationDraftReady ? styles.creatorModalSafetyActive : null]} accessibilityState={{ selected: registrationDraftReady }}>
            <View style={styles.sourceDot} />
            <Text style={[styles.creatorModalSafetyText, registrationDraftReady ? styles.creatorModalSafetyTextActive : null]} numberOfLines={2}>
              {t("draftOnly")} В· {t("noFakeApproval")} В· {t("noFakeDocuments")} В· {registrationDraftReady ? `${t(selectedRegistrationStep.title)} В· Р»РѕРєР°Р»СЊРЅС‹Р№ С‡РµСЂРЅРѕРІРёРє` : t("reviewQueueLater")}
            </Text>
          </View>

          <View style={styles.registrationBlock}>
            <Text style={styles.settingLabel}>{t(showOfficialSteps ? "registrationForm" : tile.title)}</Text>

            {showOfficialSteps ? officialRegistrationSteps.map((step) => {
              const locked = !step.draftSupported;
              const active = !locked && selectedRegistrationDraft === step.title;
              return (
                <Pressable
                  key={step.title}
                  style={[styles.registrationStep, active ? styles.registrationStepActive : null, locked ? styles.registrationStepLocked : null]}
                  onPress={() => {
                    if (locked) {
                      return;
                    }
                    setSelectedRegistrationDraft((current) => current === step.title ? null : step.title);
                  }}
                  disabled={locked}
                  accessibilityState={{ selected: active, disabled: locked }}
                  accessibilityLabel={`${t(step.title)} В· ${locked ? t("providerNotConfigured") : active ? "Р»РѕРєР°Р»СЊРЅС‹Р№ С‡РµСЂРЅРѕРІРёРє" : t(step.status)}`}
                >
                  <View style={[styles.registrationStepIcon, active ? styles.registrationStepIconActive : null, locked ? styles.registrationStepIconLocked : null]}>
                    <Ionicons name={locked ? "lock-closed-outline" : step.icon} size={20} color={active ? "#09070D" : locked ? "#8D8796" : "#F2C75B"} />
                  </View>
                  <View style={styles.registrationStepText}>
                    <Text style={[styles.registrationStepTitle, active ? styles.registrationStepTitleActive : null, locked ? styles.registrationStepTitleLocked : null]}>{t(step.title)}</Text>
                    <Text style={[styles.registrationStepStatus, active ? styles.registrationStepStatusActive : null, locked ? styles.registrationStepStatusLocked : null]}>{active ? `${t(step.status)} В· Р»РѕРєР°Р»СЊРЅС‹Р№ С‡РµСЂРЅРѕРІРёРє` : locked ? `${t(step.status)} В· ${t("providerNotConfigured")}` : t(step.status)}</Text>
                  </View>
                </Pressable>
              );
            }) : (
              <View style={[styles.registrationStep, styles.registrationStepLocked]} accessibilityState={{ disabled: true }}>
                <View style={styles.registrationStepIcon}>
                  <Ionicons name="lock-closed-outline" size={20} color="#F2C75B" />
                </View>
                <View style={styles.registrationStepText}>
                  <Text style={styles.registrationStepTitle}>{t("providerNotConfigured")}</Text>
                  <Text style={styles.registrationStepStatus}>{t("reviewQueueLater")}</Text>
                </View>
              </View>
            )}
          </View>

          <Pressable
            style={[styles.submitReviewButton, !registrationDraftReady ? styles.submitReviewButtonDisabled : styles.submitReviewButtonDraft]}
            onPress={openVerificationDraft}
            disabled={!registrationDraftReady}
            accessibilityState={{ selected: registrationDraftReady, disabled: !registrationDraftReady }}
            accessibilityLabel={registrationDraftReady ? `${t("creatorVerification")} В· Р»РѕРєР°Р»СЊРЅС‹Р№ С‡РµСЂРЅРѕРІРёРє` : `${t("submitForReview")} В· ${t("reviewQueueLater")}`}
          >
            <Text style={[styles.submitReviewText, !registrationDraftReady ? styles.submitReviewTextDisabled : styles.submitReviewTextDraft]}>
              {registrationDraftReady ? `${t("creatorVerification")} В· С‡РµСЂРЅРѕРІРёРє` : t("submitForReview")}
            </Text>
          </Pressable>
        </Pressable>
      </Pressable>
    </Modal>
  );
}

function isCreatorTileDraftSupported(action: CreatorTileAction): boolean {
  return action === "setup" || action === "official" || action === "documents";
}

function ProfileStatusPill({ t }: { t: (key: StreamTextKey) => string }) {
  return (
    <View style={styles.profileStatusPill}>
      <View style={styles.sourceDot} />
      <Text style={styles.profileStatusText} numberOfLines={1}>{t("verificationPending")}</Text>
    </View>
  );
}

function ProfileScreen({ t }: { t: (key: StreamTextKey) => string }) {
  const [selectedTile, setSelectedTile] = useState<CreatorTile | null>(null);
  const [verificationOpen, setVerificationOpen] = useState(false);

  return (
    <View style={styles.profile}>
      <View style={styles.profileHero}>
        <LinearGradient colors={["#191421", "#0C0A11"]} style={styles.profileHeroGradient}>
          <View style={styles.avatar} />
          <View style={styles.profileHeroText}>
            <Text style={styles.profileTitle} numberOfLines={1}>{t("creatorStudio")}</Text>
            <Text style={styles.profileSubtitle} numberOfLines={2}>{t("realDataOnly")} В· {t("providerLater")}</Text>
          </View>
          <ProfileStatusPill t={t} />
        </LinearGradient>
      </View>

      <StreamProfileSetupPanel />

      <View style={styles.creatorGrid}>
        {creatorTiles.map((tile) => {
          const selected = selectedTile?.action === tile.action;
          const draftSupported = isCreatorTileDraftSupported(tile.action);
          const locked = !draftSupported;
          return (
            <Pressable
              key={`${tile.title}-${tile.status}`}
              style={[styles.creatorTile, selected && draftSupported ? styles.creatorTileActive : null, locked ? styles.creatorTileLocked : null]}
              onPress={() => {
                if (!draftSupported) {
                  return;
                }
                setSelectedTile(tile);
              }}
              disabled={locked}
              accessibilityState={{ selected: selected && draftSupported, disabled: locked }}
              accessibilityLabel={`${t(tile.title)} В· ${locked ? t("providerNotConfigured") : t(tile.status)}`}
            >
              <View style={[styles.creatorIconBox, selected && draftSupported ? styles.creatorIconBoxActive : null, locked ? styles.creatorIconBoxLocked : null]}>
                <Ionicons name={tile.icon} size={25} color={selected && draftSupported ? "#09070D" : locked ? "#8D8796" : "#F2C75B"} />
              </View>
              <Text style={[styles.creatorTileTitle, selected && draftSupported ? styles.creatorTileTitleActive : null, locked ? styles.creatorTileTitleLocked : null]} numberOfLines={2}>{t(tile.title)}</Text>
              <Text style={[styles.creatorTileStatus, selected && draftSupported ? styles.creatorTileStatusActive : null, locked ? styles.creatorTileStatusLocked : null]} numberOfLines={2}>
                {locked ? `${t(tile.status)} В· ${t("providerNotConfigured")}` : t(tile.status)}
              </Text>
            </Pressable>
          );
        })}
      </View>

      <StreamCreatorVerificationPanel
        visible={verificationOpen}
        onClose={() => setVerificationOpen(false)}
        t={t}
      />

      <CreatorRegistrationModal
        visible={Boolean(selectedTile)}
        tile={selectedTile}
        onClose={() => setSelectedTile(null)}
        onOpenVerification={() => {
          setSelectedTile(null);
          setVerificationOpen(true);
        }}
        t={t}
      />
    </View>
  );
}

export default function StreamScreen() {
  const insets = useSafeAreaInsets();
  const { height, width } = useWindowDimensions();
  const { language } = useI18n();
  const t = useMemo(() => createStreamTranslator(language), [language]);
  const [active, setActive] = useState<Tab>("home");

  const topLimit = Math.max(insets.top + 12, 32);
  const bottomTabBottom = Math.max(insets.bottom + 4, 8);
  const bottomLimit = bottomTabBottom + TAB_BAR_HEIGHT + 8;

  return (
    <View style={styles.container}>
      <StatusBar style="light" />
      {active === "home" ? (
        <HomeScreen t={t} topLimit={topLimit} bottomLimit={bottomLimit} screenHeight={height} screenWidth={width} language={language} onOpenTab={setActive} />
      ) : active === "live" ? (
        <View style={[styles.liveTabFrame, { paddingTop: topLimit, paddingBottom: bottomLimit }]}>
          <LiveSetupScreen t={t} language={language} />
        </View>
      ) : (
        <ScrollView
          showsVerticalScrollIndicator={false}
          keyboardShouldPersistTaps="handled"
          nestedScrollEnabled={true}
          overScrollMode="never"
          contentContainerStyle={[styles.scroll, { paddingTop: topLimit, paddingBottom: bottomLimit + 28 }]}
          scrollIndicatorInsets={{ top: topLimit, bottom: bottomLimit + 28 }}
        >
          {active === "business" ? <BusinessStreamScreen t={t} /> : null}
          {active === "shorts" ? <ShortsScreen t={t} /> : null}
          {active === "profile" ? <ProfileScreen t={t} /> : null}
        </ScrollView>
      )}
      <BottomTabs active={active} setActive={setActive} t={t} bottom={bottomTabBottom} screenWidth={width} />
    </View>
  );
}

